def solution(s):
    signStack = []
    stack = []
    num = 0
    index = 0
    while index < len(s):
        char = s[index]
        if char.isdigit():
            num = num * 10 + int(char)
        elif char in {"a", "s"}:
            # add, sub
            if s[index:index + 4] == "add(":
                signStack.append("+")
                index += 3
            elif s[index:index + 4] == "sub(":
                signStack.append("-")
                index += 3
            else:
                return exception(f"syntax error at position {index} for in string {s}")
        elif char == ",":
            stack.append(num)
            num = 0
        elif char == ")":
            if num:
                stack.append(num)
                num = 0
            first, second = stack.pop(), stack.pop()
            currSign = signStack.pop()
            if currSign == "+":
                stack.append(first + second)
            elif currSign == "-":
                stack.append(second - first)
        elif char != " ":
            return exception(f"syntax error at position {index} for in string {s}")
        index += 1
    return sum(stack)
