#include <bits/stdc++.h>
using namespace std;

int skipWhitespace(string expression, int &index) {
    while (index < expression.size() && expression[index] == ' ') {
        index++;
    }
    return index;
}

int parseExpression(string expression, int &index) {
    while (index < expression.size()) {
        index = skipWhitespace(expression, index);
        string operation = "";
        int value1, value2;

        if (isalpha(expression[index])) {
            if (expression.substr(index, 3) == "add") {
                operation = "ADD";
                index += 3;
            } else if (expression.substr(index, 3) == "sub") {
                operation = "SUB";
                index += 3;
            } else {
                throw runtime_error("Invalid operation");
            }

            index = skipWhitespace(expression, index);

            if (expression[index] == '(') {
                index += 1;
                index = skipWhitespace(expression, index);

                if (isalpha(expression[index])) {
                    value1 = parseExpression(expression, index);
                } else {
                    value1 = 0;
                    while (isdigit(expression[index])) {
                        value1 = value1 * 10 + (expression[index] - '0');
                        index += 1;
                    }
                }

                index = skipWhitespace(expression, index);
                if (expression[index] == ',') {
                    index += 1;
                } else {
                    throw runtime_error("Expected ','");
                }

                index = skipWhitespace(expression, index);
                if (isalpha(expression[index])) {
                    value2 = parseExpression(expression, index);
                } else {
                    value2 = 0;
                    while (isdigit(expression[index])) {
                        value2 = value2 * 10 + (expression[index] - '0');
                        index += 1;
                    }
                }

                index = skipWhitespace(expression, index);
                if (expression[index] == ')') {
                    index += 1;
                    return (operation == "ADD") ? (value1 + value2) : (value1 - value2);
                } else {
                    throw runtime_error("Expected ')'");
                }
            } else {
                throw runtime_error("Expected '('");
            }
        } else {
            throw runtime_error("Invalid expression");
        }
    }
    return 0;
}

int main() {
    string a = "add(1. sub    (3, 2))";
    int index = 0;
    cout << parseExpression(a, index);
}

Here is my JavaScript code with testcases. Copy paste this in console and try it out.
Its iterative, leverages stack. 
Key operations ->
1. skip whitespaces
2. Keep on accumulating chars unless we hit - '(', ',', ')'
3. push acc instruction in stack
4. if curr char is -> "(" or ","
    -> continue usual operations with next index
5. if curr char is -> ")"
    -> pop out the last 3 values [operator, num1, num2] from stack, execute operation and then push back the result.
6. Basic error handling for "bad" operators.

T:O(N) and S: O(M) where M is the length of token.

```javaScript
function calculate(expression) {
    const stack = [];
    let i = 0;
    let currentToken = '';
    while (i < expression.length) {
        const currChar = expression[i++];
        if (currChar === ' ') continue; // Skip whitespace
        if (['(', ')', ','].includes(currChar)) {
            if (currentToken !== '') {
                stack.push(currentToken.trim());
                currentToken = '';
            }
            if (currChar === ')') {
                try {
                    const num2 = parseOperand(stack.pop(), i);
                    const num1 = parseOperand(stack.pop(), i);
                    const operator = stack.pop();
                    stack.push(`${evaluate(num1, num2, operator)}`);
                } catch (err) {
                    throw new SyntaxError(`Syntax error at position ${i}: ${err.message}`);
                }
            }
        } else {
            currentToken += currChar;
        }
    }
    return stack.pop();
}

function parseOperand(token, position) {
    if (token === undefined || isNaN(parseInt(token))) {
        throw new Error(`Invalid operand "${token}" at position ${position}`);
    }
    return parseInt(token);
}

function evaluate(num1, num2, operator) {
    if (operator === 'add') return num1 + num2;
    if (operator === 'sub') return num1 - num2;
    throw new Error(`Invalid operator "${operator}"`);
}
```
