    static int evaluate(String input) {
        return parseExpression(input.trim(), new int[]{0});
    }

    private static int parseExpression(String input, int[] pos) {
        // Skip spaces and get operation
        while (pos[0] < input.length() && input.charAt(pos[0]) == ' ') pos[0]++;
        String operation = input.substring(pos[0], pos[0] + 3);
        pos[0] += 4; // Skip 'add(' or 'sub('

        // Get first argument
        int arg1 = parseArgument(input, pos);

        // Skip comma and spaces
        pos[0]++;
        while (pos[0] < input.length() && input.charAt(pos[0]) == ' ') pos[0]++;

        // Get second argument
        int arg2 = parseArgument(input, pos);

        // Skip closing parenthesis
        pos[0]++;

        return "add".equals(operation) ? arg1 + arg2 : arg1 - arg2;
    }

    private static int parseArgument(String input, int[] pos) {
        // Skip spaces
        while (pos[0] < input.length() && input.charAt(pos[0]) == ' ') pos[0]++;

        // Check if it's a nested expression
        if (pos[0] + 2 < input.length() && 
            (input.substring(pos[0], pos[0] + 3).equals("add") || 
             input.substring(pos[0], pos[0] + 3).equals("sub"))) {
            return parseExpression(input, pos);
        }

        // Parse number
        StringBuilder num = new StringBuilder();
        while (pos[0] < input.length() && 
               (Character.isDigit(input.charAt(pos[0])) || input.charAt(pos[0]) == '-')) {
            num.append(input.charAt(pos[0]));
            pos[0]++;
        }
        return Integer.parseInt(num.toString());
    }
